import scala.math.Long.MaxValue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
    if (m == 1 && n == 1) {
        return 1L
    }

    val M = m.toInt
    val N = n.toInt
    val INF = Long.MaxValue

    val dp0 = Array.ofDim[Long](M, N)
    val dp1 = Array.ofDim[Long](M, N)

    for (i <- 0 until M) {
        for (j <- 0 until N) {
            dp0(i)(j) = INF
            dp1(i)(j) = INF
        }
    }

    dp1(0)(0) = 1L

    var ans = INF

    for (i <- 0 until M) {
        for (j <- 0 until N) {
            if (i == M - 1 && j == N - 1) {
                var cost1 = INF
                if (i > 0 && dp1(i - 1)(j) < INF) {
                    cost1 = math.min(cost1, dp1(i - 1)(j) + (i + 1L) * (j + 1L))
                }
                if (j > 0 && dp1(i)(j - 1) < INF) {
                    cost1 = math.min(cost1, dp1(i)(j - 1) + (i + 1L) * (j + 1L))
                }
                ans = cost1
            } else {
                if (i != 0 || j != 0) {
                    var minValue = INF
                    if (i > 0 && dp1(i - 1)(j) < INF) {
                        minValue = math.min(minValue, dp1(i - 1)(j) + (i + 1L) * (j + 1L))
                    }
                    if (j > 0 && dp1(i)(j - 1) < INF) {
                        minValue = math.min(minValue, dp1(i)(j - 1) + (i + 1L) * (j + 1L))
                    }
                    dp0(i)(j) = minValue
                }
                if (dp0(i)(j) < INF) {
                    dp1(i)(j) = dp0(i)(j) + waitCost(i)(j)
                }
            }
        }
    }

    if (ans == INF) -1L else ans
}
```

### Explanation
1. **Initialization**:
   - For a 1x1 grid, return the entry cost of (0, 0) directly.
   - Initialize DP arrays `dp0` and `dp1` with `INF` (infinity) to represent unreachable states.
   - Set `dp1[0][0] = 1` for the starting position (0, 0) at the first odd second.

2. **Grid Processing**:
   - Traverse each cell (i, j) in row-major order.
   - For the destination (m-1, n-1):
     - Compute the minimum cost from its top and left neighbors during their odd seconds, plus the entry cost for (m-1, n-1).
     - Store this cost in `ans`.
   - For other cells:
     - **dp0 Update**: Compute the minimum cost to reach (i, j) during an even second from top or left neighbors in their odd states, plus the entry cost for (i, j).
     - **dp1 Update**: Set to `dp0[i][j] + waitCost[i][j]`, representing the cost after waiting during an even second.

3. **Result Extraction**:
   - Return the computed `ans` for the destination, or `-1` if the destination is unreachable (though the problem ensures a valid path exists).

This approach efficiently computes the minimal path cost by leveraging dynamic programming to track states based on movement and waiting rules, ensuring optimal performance for grid-based pathfinding problems.
